UPDATE blog_posts 
SET meta_title = 'Sunrun Complaints California 2026 — NEM 3.0 Fraud & Legal Options',
    meta_description = 'California Sunrun customers hit hardest by NEM 3.0 — savings cut 75%. If you were misled about bill savings, you may have grounds to cancel. Free case review.'
WHERE slug = 'sunrun-complaints-california';

UPDATE blog_posts 
SET meta_title = 'ADT Solar Complaints 2026 — Cancel Your Contract After Acquisition',
    meta_description = 'ADT Solar was sold to SunPower, which then collapsed. If your warranty is void and savings never materialized, you may have grounds to cancel. Free case review.'
WHERE slug = 'adt-solar-complaints';

SELECT slug, meta_title, meta_description FROM blog_posts WHERE slug IN ('sunrun-complaints-california', 'adt-solar-complaints');

